1. import { createServerClient } from '@supabase/ssr';
2. import { NextRequest, NextResponse } from 'next/server';
3. import { getSupabaseEnv } from '@/lib/supabase/config';
4. 
5. function copyCookies(source: NextResponse, target: NextResponse) {
6.   source.cookies.getAll().forEach((cookie) => {
7.     target.cookies.set(cookie);
8.   });
9. }
10. 
11. export async function middleware(request: NextRequest) {
12.   const response = NextResponse.next({
13.     request: {
14.       headers: request.headers,
15.     },
16.   });
17. 
18.   const { supabaseUrl, supabaseAnonKey } = getSupabaseEnv();
19. 
20.   const supabase = createServerClient(supabaseUrl, supabaseAnonKey, {
21.     cookies: {
22.       getAll() {
23.         return request.cookies.getAll();
24.       },
25.       setAll(cookiesToSet) {
26.         cookiesToSet.forEach(({ name, value, options }) => {
27.           response.cookies.set(name, value, options);
28.         });
29.       },
30.     },
31.   });
32. 
33.   const {
34.     data: { user },
35.   } = await supabase.auth.getUser();
36. 
37.   const { pathname } = request.nextUrl;
38. 
39.   if ((pathname === '/login' || pathname === '/signup' || pathname === '/') && user) {
40.     const redirectResponse = NextResponse.redirect(
41.       new URL('/dashboard', request.url),
42.     );
43.     copyCookies(response, redirectResponse);
44.     return redirectResponse;
45.   }
46. 
47.   if ((pathname.startsWith('/dashboard') || pathname.startsWith('/settings')) && !user) {
48.     const redirectResponse = NextResponse.redirect(
49.       new URL('/login', request.url),
50.     );
51.     copyCookies(response, redirectResponse);
52.     return redirectResponse;
53.   }
54. 
55.   return response;
56. }
57. 
58. export const config = {
59.   matcher: ['/dashboard/:path*', '/settings/:path*', '/login', '/signup', '/'],
60. };
61.

