3. import { createAdminClient } from '@/lib/supabase/admin';
4. import { createClient } from '@/lib/supabase/server';
5. import {
6.   normalizeUsername,
7.   validateUsername,
8. } from '@/lib/username';
9. import { isUsernameAvailable } from '@/lib/supabase/username';
10. import { sendWelcomeEmail } from '@/lib/resend/welcome-email';
11. import { redirect } from 'next/navigation';
12. 
13. export type AuthState = {
14.   error?: string;
15.   message?: string;
16. };
17. 
18. function readField(formData: FormData, key: string, trim = true) {
19.   const value = formData.get(key);
20. 
21.   if (typeof value !== 'string') {
22.     return '';
23.   }
24. 
25.   return trim ? value.trim() : value;
26. }
27. 
28. async function cleanupCreatedUser(
29.   supabase: Awaited<ReturnType<typeof createClient>>,
30.   adminClient: ReturnType<typeof createAdminClient>,
31.   userId: string,
32. ) {
33.   const { error: deleteError } = await adminClient.auth.admin.deleteUser(userId);
34.   const { error: signOutError } = await supabase.auth.signOut();
35. 
36.   return deleteError?.message ?? signOutError?.message ?? null;
37. }
38. 
39. export async function loginAction(
40.   _: AuthState,
41.   formData: FormData,
42. ): Promise<AuthState> {
43.   const email = readField(formData, 'email');
44.   const password = readField(formData, 'password');
45. 
46.   if (!email || !password) {
47.     return {
48.       error: 'Email and password are required.',
49.     };
50.   }
51. 
52.   const supabase = await createClient();
53.   const { error } = await supabase.auth.signInWithPassword({
54.     email,
55.     password,
56.   });
57. 
58.   if (error) {
59.     return {
60.       error: error.message,
61.     };
62.   }
63. 
64.   redirect('/dashboard');
65. }
66. 
67. export async function signupAction(
68.   _: AuthState,
69.   formData: FormData,
70. ): Promise<AuthState> {
71.   const username = normalizeUsername(readField(formData, 'username', false));
72.   const email = readField(formData, 'email');
73.   const password = readField(formData, 'password');
74. 
75.   const usernameError = validateUsername(username);
76. 
77.   if (usernameError) {
78.     return {
79.       error: usernameError,
80.     };
81.   }
82. 
83.   if (!email || !password) {
84.     return {
85.       error: 'Email and password are required.',
86.     };
87.   }
88. 
89.   const supabase = await createClient();
90.   const adminClient = createAdminClient();
91. 
92.   try {
93.     const availableBeforeSignup = await isUsernameAvailable(username);
94. 
95.     if (!availableBeforeSignup) {
96.       return {
97.         error: 'Username is already taken.',
98.       };
99.     }
100.   } catch (error) {
101.     const message = error instanceof Error ? error.message : 'Unknown error';
102. 
103.     return {
104.       error: message,
105.     };
106.   }
107. 
108.   const { data, error } = await supabase.auth.signUp({
109.     email,
110.     password,
111.   });
112. 
113.   if (error) {
114.     return {
115.       error: error.message,
116.     };
117.   }
118. 
119.   const userId = data.user?.id;
120. 
121.   if (!userId) {
122.     await supabase.auth.signOut();
123.     return {
124.       error: 'Signup succeeded, but the auth user record was not returned.',
