138.     }
139.   } catch (error) {
140.     const cleanupError = await cleanupCreatedUser(supabase, adminClient, userId);
141.     const message = error instanceof Error ? error.message : 'Unknown error';
142. 
143.     return {
144.       error: cleanupError
145.         ? `${message} Cleanup failed: ${cleanupError}`
146.         : message,
147.     };
148.   }
149. 
