                           : 'bg-black/5 text-black/65'
                       }`}
                     >
                       {bookmark.is_public ? 'Public' : 'Private'}
                     </span>
                   </div>
                 </li>
               ))}
             </ul>
           )}
         </div>
       </div>
     </main>
   );
 }

